import React, { useEffect, useRef } from "react";
import "./HowItWorks.css";

const steps = [
    {
        num: "01", tag: "Step One", title: "Upload to IPFS", headline: "CONTENT-ADDRESSED",
        desc: "Your PDF is uploaded to the InterPlanetary File System via Pinata. IPFS stores files by content — it runs your file through SHA-256 hashing and returns a Content Identifier (CID): a cryptographic fingerprint of every byte in your document. Any modification changes the CID entirely.",
        details: ["SHA-256 cryptographic hashing","Pinata pinning ensures global availability","Any modification changes the CID entirely","CID is mathematically unique to your document"],
        code: "const cid = await uploadToPinata(file);\n// → bafybeigdyrzt5sfp7udm7...",
        img: "https://images.unsplash.com/photo-1558494949-ef010cbdcc31?w=1000&q=80",
        bgWord: "HASH", accent: "#b8922a",
    },
    {
        num: "02", tag: "Step Two", title: "Register On-Chain", headline: "IMMUTABLE",
        desc: "Your CID, Ethereum wallet address, and a network-consensus timestamp are written into a Solidity smart contract on Polygon. The contract permanently rejects any future attempt to register the same CID — making you the irrefutable first. No one can alter this record.",
        details: ["msg.sender cryptographically verifies authorship","block.timestamp set by network consensus","Duplicate CIDs rejected at contract level","No admin, no backdoor, fully immutable code"],
        code: "await registry.submitPaper(cid);\n// Confirmed at block #1,284,920",
        img: "https://images.unsplash.com/photo-1639322537228-f710d846310a?w=1000&q=80",
        bgWord: "CHAIN", accent: "#3d7fff",
    },
    {
        num: "03", tag: "Step Three", title: "Verify Anywhere", headline: "TRUSTLESS",
        desc: "Anyone in the world can call getPaper() with a CID. The blockchain returns the author address, block timestamp, and full precedence record — instantly, permissionlessly, without any trusted third party. This is what trustless verification means.",
        details: ["Read-only view function — zero gas cost","Anyone can verify, no account needed","Returns author, timestamp, existence status","Verifiable for as long as the blockchain exists"],
        code: "const [cid, author, ts, exists]\n  = await registry.getPaper(cid);",
        img: "https://images.unsplash.com/photo-1451187580459-43490279c0fa?w=1000&q=80",
        bgWord: "VERIFY", accent: "#1a6b5a",
    },
];

function Step({ step, index }) {
    const ref = useRef(null);
    useEffect(() => {
        const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) { ref.current?.classList.add("how-step--visible"); io.unobserve(ref.current); } }, { threshold: 0.15 });
        if (ref.current) io.observe(ref.current);
        return () => io.disconnect();
    }, []);
    const isEven = index % 2 === 1;
    return (
        <div className={`how-step ${isEven ? "how-step--reverse" : ""}`} ref={ref}>
            <div className="how-step__image-wrap">
                <img src={step.img} alt={step.title} className="how-step__img" loading="lazy" />
                <div className="how-step__img-overlay" />
                <div className="how-step__img-num">{step.num}</div>
                <div className="how-step__bg-word" style={{ color: `${step.accent}12` }}>{step.bgWord}</div>
                <div className="how-step__code-overlay"><pre className="how-step__code">{step.code}</pre></div>
            </div>
            <div className="how-step__content">
                <div className="how-step__tag" style={{ color: step.accent }}>{step.tag} · {step.num}</div>
                <div className="how-step__headline">{step.headline}</div>
                <h3 className="how-step__title">{step.title}</h3>
                <p className="how-step__desc">{step.desc}</p>
                <ul className="how-step__details">
                    {step.details.map(d => (
                        <li className="how-step__detail" key={d}>
                            <span className="how-step__detail-bullet" style={{ borderColor: step.accent }}><span style={{ background: step.accent }} /></span>
                            {d}
                        </li>
                    ))}
                </ul>
            </div>
        </div>
    );
}

export default function HowItWorks() {
    return (
        <section className="how-section" id="how">
            <div className="how-header">
                <div className="how-header__bleed">PROCESS</div>
                <div className="how-header__label">The Process</div>
                <h2 className="how-header__title">Three steps.<br />Permanent proof.</h2>
            </div>
            {steps.map((step, i) => <Step key={step.num} step={step} index={i} />)}
        </section>
    );
}
